import os,base64,stat

b=os.path.dirname(os.path.abspath(__file__))
d={}

d['cywallearn.py']=''
d['modules/generator.py']=''
d['modules/analyzer.py']=''
d['modules/__init__.py']='IyBDeXdhbGxlYXJuIFVuaGFja2VkCl9fdmVyc2lvbl9fID0gIjEuMC4wIgo='

for f,c in d.items():
  p=os.path.join(b,f)
  os.makedirs(os.path.dirname(p),exist_ok=True)
  open(p,"wb").write(base64.b64decode(c))
  print("OK: "+f)

os.chmod(os.path.join(b,"cywallearn.py"),stat.S_IRWXU|stat.S_IRGRP|stat.S_IXGRP|stat.S_IROTH|stat.S_IXOTH)
print("Done! Run: python3 cywallearn.py")
